css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #f7f8fa; color: #1a1a1a; }
.app { max-width: 1000px; margin: 0 auto; padding: 40px 24px; }
.steps { display: flex; align-items: center; justify-content: center; margin-bottom: 40px; }
.step { display: flex; align-items: center; gap: 10px; font-size: 13.5px; font-weight: 700; color: #bbb; }
.step.active, .step.done { color: #6366f1; }
.step span { width: 28px; height: 28px; border-radius: 50%; background: #eee; color: #999; display: flex; align-items: center; justify-content: center; font-size: 13px; }
.step.active span, .step.done span { background: #6366f1; color: white; }
.step-line { width: 60px; height: 2px; background: #eee; margin: 0 14px; }
.content { display: grid; grid-template-columns: 1.6fr 1fr; gap: 30px; }
.panel { display: none; background: white; border-radius: 18px; padding: 32px; }
.panel.active { display: block; }
.panel h2 { font-size: 22px; font-weight: 800; margin-bottom: 22px; }
.form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; margin-bottom: 22px; }
.field.full { grid-column: span 2; }
.field label { display: block; font-size: 12.5px; font-weight: 700; color: #999; margin-bottom: 8px; }
.field input { width: 100%; padding: 13px 16px; border: 1px solid #eee; border-radius: 10px; font-size: 14px; outline: none; }
.field input:focus { border-color: #6366f1; }
.shipping-options { display: flex; flex-direction: column; gap: 12px; margin-bottom: 26px; }
.ship-option { display: flex; justify-content: space-between; align-items: center; border: 1.5px solid #eee; border-radius: 12px; padding: 16px 18px; cursor: pointer; }
.ship-option.active { border-color: #6366f1; background: #f5f5ff; }
.ship-option strong { display: block; font-size: 14px; margin-bottom: 2px; }
.ship-option span { font-size: 12.5px; color: #999; }
.ship-price { font-weight: 800; font-size: 14px; }
.payment-methods { display: flex; gap: 10px; margin-bottom: 22px; flex-wrap: wrap; }
.pay-option { background: #f5f5f7; border: 1.5px solid transparent; padding: 12px 20px; border-radius: 10px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.pay-option.active { background: #f5f5ff; border-color: #6366f1; color: #6366f1; }
.btn-primary { width: 100%; background: #6366f1; color: white; border: none; padding: 16px; border-radius: 12px; font-size: 14.5px; font-weight: 700; cursor: pointer; margin-bottom: 10px; }
.btn-link { width: 100%; background: none; border: none; color: #999; font-size: 13.5px; font-weight: 600; cursor: pointer; padding: 8px; }
.success-icon { width: 64px; height: 64px; border-radius: 50%; background: #dcfce7; color: #16a34a; display: flex; align-items: center; justify-content: center; font-size: 28px; font-weight: 800; margin: 0 auto 20px; }
.panel#panelConfirm { text-align: center; }
.panel#panelConfirm h2 { margin-bottom: 12px; }
.panel#panelConfirm p { color: #999; font-size: 14px; line-height: 1.7; margin-bottom: 26px; }
.summary { background: white; border-radius: 18px; padding: 28px; align-self: start; }
.summary h3 { font-size: 17px; font-weight: 800; margin-bottom: 18px; }
.summary-item { display: flex; justify-content: space-between; font-size: 13.5px; color: #777; padding: 8px 0; }
.summary-item.total { font-size: 17px; font-weight: 800; color: #1a1a1a; }
.summary-divider { height: 1px; background: #eee; margin: 8px 0; }
@media (max-width: 800px) { .content { grid-template-columns: 1fr; } .form-grid { grid-template-columns: 1fr; } .field.full { grid-column: span 1; } .step-line { width: 30px; } }

js:
let shippingCost = 0;
const subtotal = 5698;

function goToStep(step) {
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.step').forEach(s => { s.classList.remove('active'); });

  if (step === 1) document.getElementById('panelShipping').classList.add('active');
  if (step === 2) document.getElementById('panelPayment').classList.add('active');
  if (step === 3) document.getElementById('panelConfirm').classList.add('active');

  document.getElementById('step1Dot').classList.add(step > 1 ? 'done' : 'active');
  document.getElementById('step2Dot').classList.add(step === 2 ? 'active' : step > 2 ? 'done' : '');
  document.getElementById('step3Dot').classList.add(step === 3 ? 'active' : '');
}

function selectShipping(el, cost) {
  document.querySelectorAll('.ship-option').forEach(o => o.classList.remove('active'));
  el.classList.add('active');
  shippingCost = cost;
  document.getElementById('shippingCost').textContent = cost === 0 ? 'Ücretsiz' : `₺${cost}`;
  document.getElementById('totalCost').textContent = `₺${(subtotal + cost).toLocaleString('tr-TR')}`;
}

function selectPayment(el) {
  document.querySelectorAll('.pay-option').forEach(o => o.classList.remove('active'));
  el.classList.add('active');
}
